<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***JWTAuthenticationManager*PartofSecurity&AuthenticationSystem*/classJWTAuth{privatestatic$secretKey;privatestatic$algorithm='HS256';privatestatic$tokenLifetime=86400;/24hours/***Initializewithsecretkeyfromconfig*/publicstaticfunctioninit(){if(!defined('JWT_SECRET')){define('JWT_SECRET','sprin-secret-key-'.date('Y-m-d'));}self::$secretKey=JWT_SECRET;}/***GenerateJWTtoken*/publicstaticfunctiongenerateToken($payload){self::init();$header=json_encode(['typ'=>'JWT','alg'=>self::$algorithm]);$time=time();$tokenPayload=array_merge($payload,['iat'=>$time,/Issuedat'exp'=>$time+self::$tokenLifetime,/Expiration'iss'=>'sprin-system',/Issuer'aud'=>'sprin-api'/Audience]);$base64Header=str_replace(['+','/','='],['-','_',''],base64_encode($header));$base64Payload=str_replace(['+','/','='],['-','_',''],base64_encode(json_encode($tokenPayload)));$signature=hash_hmac('sha256',$base64Header.".".$base64Payload,self::$secretKey,true);$base64Signature=str_replace(['+','/','='],['-','_',''],base64_encode($signature));return$base64Header.".".$base64Payload.".".$base64Signature;}/***VerifyanddecodeJWTtoken*/publicstaticfunctionverifyToken($token){self::init();$parts=explode('.',$token);if(count($parts)!==3){return['valid'=>false,'error'=>'Invalidtokenformat'];}list($base64Header,$base64Payload,$base64Signature)=$parts;/Verifysignature$signature=hash_hmac('sha256',$base64Header.".".$base64Payload,self::$secretKey,true);$base64ComputedSignature=str_replace(['+','/','='],['-','_',''],base64_encode($signature));if(!hash_equals($base64Signature,$base64ComputedSignature)){return['valid'=>false,'error'=>'Invalidsignature'];}/Decodepayload$payload=json_decode(base64_decode(str_replace(['-','_'],['+','/'],$base64Payload)),true);if(!$payload){return['valid'=>false,'error'=>'Invalidpayload'];}/Checkexpirationif(isset($payload['exp'])&&$payload['exp']<time()){return['valid'=>false,'error'=>'Tokenexpired'];}return['valid'=>true,'payload'=>$payload];}/***Gettokenfromrequestheaders*/publicstaticfunctiongetTokenFromHeaders(){$headers=getallheaders();if(isset($headers['Authorization'])){$authHeader=$headers['Authorization'];if(strpos($authHeader,'Bearer')===0){returnsubstr($authHeader,7);}}/Checkqueryparameterasfallbackif(isset(filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'token',FILTER_DEFAULT))){returnfilter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'token',FILTER_DEFAULT);}returnnull;}/***AuthenticateAPIrequest*/publicstaticfunctionauthenticate(){$token=self::getTokenFromHeaders();if(!$token){http_response_code(401);header('Content-Type:application/json');echojson_encode(['success'=>false,'message'=>'Authenticationrequired','timestamp'=>date('c')]);exit;}$result=self::verifyToken($token);if(!$result['valid']){http_response_code(401);header('Content-Type:application/json');echojson_encode(['success'=>false,'message'=>$result['error'],'timestamp'=>date('c')]);exit;}return$result['payload'];}/***Refreshtoken*/publicstaticfunctionrefreshToken($token){$result=self::verifyToken($token);if(!$result['valid']){return['success'=>false,'error'=>$result['error']];}/Removeexpandiatfromoldpayload$payload=$result['payload'];unset($payload['iat']);unset($payload['exp']);unset($payload['iss']);unset($payload['aud']);/Generatenewtoken$newToken=self::generateToken($payload);return['success'=>true,'token'=>$newToken,'expires_in'=>self::$tokenLifetime];}/***Settokenlifetime*/publicstaticfunctionsetTokenLifetime($seconds){self::$tokenLifetime=$seconds;}/***Gettokenlifetime*/publicstaticfunctiongetTokenLifetime(){returnself::$tokenLifetime;}}/Auto-initializeJWTAuth::init();?>
